import React, { useState } from "react";
import Dice from "react-dice-roll";

const boardImage = "/torahpoly_board.png";

const bereshitCard = {
  name: "Bereshit",
  questions: [
    {
      question: "What day was Adam born?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "What day was not 'good' but 'very' good?",
      answer: "The 6th day",
      points: 20,
    },
    {
      question: "Where do we see adding is sometimes subtracting?",
      answer:
        "Adam added 'don't touch' the tree. The snake used this to fool Chava.",
      points: 20,
    },
  ],
};

function CardQA({ card, onFinish }) {
  const [currentQ, setCurrentQ] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);
  const [accepted, setAccepted] = useState(
    Array(card.questions.length).fill(false)
  );

  const toggleAnswer = () => setShowAnswer((v) => !v);

  const acceptCorrect = () => {
    setAccepted((prev) => {
      const copy = [...prev];
      copy[currentQ] = true;
      return copy;
    });
  };

  const prevQuestion = () => {
    setShowAnswer(false);
    setCurrentQ((i) => (i > 0 ? i - 1 : i));
  };

  const nextQuestion = () => {
    setShowAnswer(false);
    setCurrentQ((i) => (i < card.questions.length - 1 ? i + 1 : i));
  };

  const totalPoints = accepted.reduce(
    (sum, val, i) => (val ? sum + card.questions[i].points : sum),
    0
  );

  const allCorrect = accepted.every((val) => val === true);

  return (
    <div style={styles.qaContainer}>
      <h2>{card.name} Card Q&A</h2>
      <p>
        Question {currentQ + 1} of {card.questions.length}
      </p>
      <div style={styles.questionBox}>
        <p style={{ fontWeight: "bold" }}>{card.questions[currentQ].question}</p>
        {showAnswer ? (
          <p style={styles.answer}>{card.questions[currentQ].answer}</p>
        ) : (
          <button onClick={toggleAnswer} style={styles.button}>
            Reveal Answer
          </button>
        )}
      </div>
      <div style={{ marginTop: 10 }}>
        <button
          onClick={prevQuestion}
          disabled={currentQ === 0}
          style={styles.button}
        >
          Previous Question
        </button>
        <button
          onClick={nextQuestion}
          disabled={currentQ === card.questions.length - 1}
          style={{ ...styles.button, marginLeft: 10 }}
        >
          Next Question
        </button>
      </div>

      <div style={{ marginTop: 20 }}>
        {!accepted[currentQ] && showAnswer && (
          <button onClick={acceptCorrect} style={styles.acceptButton}>
            Accept Correct (Add {card.questions[currentQ].points} Zchut)
          </button>
        )}
        {accepted[currentQ] && (
          <p style={{ color: "green", fontWeight: "bold" }}>
            Accepted Correct ✔
          </p>
        )}
      </div>

      <div style={{ marginTop: 30 }}>
        <p>
          Total Zchut Points Earned: <strong>{totalPoints}</strong>
        </p>

        {allCorrect ? (
          <p style={{ color: "blue", fontWeight: "bold" }}>
            All questions answered correctly! You can proceed to the next card.
          </p>
        ) : (
          <p>You can finish now with current points or continue answering.</p>
        )}
      </div>

      <button
        onClick={() => onFinish(allCorrect, totalPoints)}
        style={{ ...styles.button, marginTop: 20 }}
      >
        Finish Q&A
      </button>
    </div>
  );
}

function App() {
  const [boardRotation, setBoardRotation] = useState(0);
  const [playerPosition, setPlayerPosition] = useState(0);
  const [turnCount, setTurnCount] = useState(1);
  const [diceRolls, setDiceRolls] = useState([]);
  const [playerName, setPlayerName] = useState("");
  const [qaMode, setQaMode] = useState(false);
  const [zchutPoints, setZchutPoints] = useState(0);

  const rotateBoard = () => {
    setBoardRotation((prev) => (prev + 90) % 360);
  };

  const finishQA = (allCorrect, points) => {
    setQaMode(false);
    setZchutPoints((prev) => prev + points);
  };

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      {!qaMode && (
        <>
          <div style={{ marginBottom: 20 }}>
            <label>
              Enter Player Name:{" "}
              <input
                type="text"
                value={playerName}
                onChange={(e) => setPlayerName(e.target.value)}
                style={styles.input}
                placeholder="Your Name"
              />
            </label>
            {playerName && (
              <p>
                Player: <strong>{playerName}</strong>
              </p>
            )}
          </div>

          <div style={{ position: "relative", display: "inline-block", marginBottom: 20 }}>
            <img
              src={boardImage}
              alt="Game Board"
              style={{
                width: 900,
                maxWidth: "95vw",
                border: "2px solid #333",
                transform: `rotate(${boardRotation}deg)`,
                transition: "transform 0.5s ease",
                borderRadius: 12,
              }}
            />

            {/* Tzadik Deck Button */}
            <button
              onClick={() => setQaMode(true)}
              style={{
                position: "absolute",
                top: "43%",
                left: "54%",
                transform: "translate(-50%, -50%)",
                padding: "6px 12px",
                fontSize: 14,
                backgroundColor: "#ffc107",
                color: "#000",
                border: "2px solid #333",
                borderRadius: 6,
                cursor: "pointer",
              }}
            >
              Tzadik Deck
            </button>

            {/* Parsha Deck Button with left side lowered 40deg */}
            <button
              onClick={() => setQaMode(true)}
              style={{
                position: "absolute",
                top: "58%",
                left: "70%",
                transformOrigin: "left center",
                transform: "translate(-50%, -50%) rotateX(40deg)",
                padding: "6px 12px",
                fontSize: 14,
                backgroundColor: "#17a2b8",
                color: "#fff",
                border: "2px solid #000",
                borderRadius: 6,
                cursor: "pointer",
              }}
            >
              Parsha Deck
            </button>
          </div>

          <button onClick={rotateBoard} style={styles.button}>
            Rotate Board 90°
          </button>

          <div style={{ marginBottom: 30, marginTop: 20 }}>
            <h2>Roll Dice</h2>
            <div style={{ display: "flex", justifyContent: "center", gap: 20 }}>
              <Dice
                sides={6}
                onRoll={(val) => {}}
                faceColor="#007bff"
                dotColor="#fff"
                disabled={qaMode}
                rollTime={1}
              />
              <Dice
                sides={6}
                onRoll={(val) => {}}
                faceColor="#007bff"
                dotColor="#fff"
                disabled={qaMode}
                rollTime={1}
              />
            </div>
            <p>Turn: {turnCount}</p>
            <p>Player Position: {playerPosition}</p>
            <p>Total Zchut Points: {zchutPoints}</p>
          </div>
        </>
      )}

      {qaMode && (
        <CardQA
          card={bereshitCard}
          onFinish={(allCorrect, points) => finishQA(allCorrect, points)}
        />
      )}
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    padding: 20,
    backgroundColor: "#f0f2f5",
    minHeight: "100vh",
    textAlign: "center",
  },
  button: {
    backgroundColor: "#007bff",
    color: "white",
    border: "none",
    borderRadius: 8,
    padding: "10px 20px",
    fontSize: 16,
    cursor: "pointer",
  },
  input: {
    fontSize: 16,
    padding: "5px 10px",
    borderRadius: 4,
    border: "1px solid #ccc",
  },
  qaContainer: {
    fontFamily: "Arial, sans-serif",
    maxWidth: 500,
    margin: "20px auto",
    padding: 20,
    border: "2px solid #333",
    borderRadius: 10,
    backgroundColor: "#fefefe",
    textAlign: "center",
  },
  questionBox: {
    marginTop: 20,
    padding: 15,
    border: "1px solid #999",
    borderRadius: 8,
    backgroundColor: "#f9f9f9",
  },
  answer: {
    marginTop: 10,
    fontStyle: "italic",
    color: "#007700",
    fontWeight: "bold",
  },
  acceptButton: {
    padding: "10px 18px",
    fontSize: 16,
    marginTop: 15,
    borderRadius: 8,
    border: "none",
    cursor: "pointer",
    backgroundColor: "#28a745",
    color: "white",
  },
};

export default App;
